CREATE TABLE trace_record(id BIGINT PRIMARY KEY AUTO_INCREMENT,event_id VARCHAR(80) NOT NULL UNIQUE,event_type VARCHAR(80) NOT NULL,aggregate_type VARCHAR(80) NOT NULL,aggregate_id VARCHAR(80) NOT NULL,actor_id VARCHAR(64) NOT NULL,organization_id VARCHAR(64) NOT NULL,trace_id VARCHAR(80) NOT NULL,payload_json JSON,previous_hash CHAR(64) NOT NULL,event_hash CHAR(64) NOT NULL,occurred_at TIMESTAMP(6) NOT NULL);CREATE INDEX idx_trace_object ON trace_record(aggregate_type,aggregate_id,occurred_at);CREATE INDEX idx_trace_actor ON trace_record(actor_id,occurred_at);
